  // ── Pricing Config ──────────────────────────────────────────────────────────
  // Reads from window.ProposalConfig (generated by build.js) if available,
  // otherwise falls back to hardcoded defaults (ADN Venezuela).

  var _cfg = window.ProposalConfig || {};

  var PricingCart = (function() {
    var state = { core: [], addons: [], retainer: null, activePackage: null };

    var services = _cfg.services || {
      'milky-branding':   { name: 'Milky Branding', price: 3500, monthly: false },
      'shakefront-full':  { name: 'Shakefront Full (CMS)', price: 13500, monthly: false },
      'shakefront-lite':  { name: 'Shakefront Lite', price: 10500, monthly: false },
      'broadcast-assets': { name: 'Activos Gráficos Para Emisión', price: 3200, monthly: false },
      'flashy-socials':   { name: 'Flashy Socials', price: 1200, monthly: false },
      'buttery-1day':     { name: 'Buttery Frames (1 día)', price: 1200, monthly: false },
      'buttery-3days':    { name: 'Buttery Frames (3 días)', price: 2180, monthly: false },
      'cold-brew':        { name: 'Cold Brew (Video)', price: 1200, monthly: false },
      'glass-cup':        { name: 'The Glass Cup (Impresos)', price: 750, monthly: false },
      'silky-edits':      { name: 'Silky Edits (Retoque)', price: 350, monthly: false },
      'barista':          { name: 'Barista (Mantenimiento)', price: 450, monthly: true },
      'hosting-domain':   { name: 'Hosting + Dominio + Email', price: 320, monthly: false },
      'multilingue':      { name: 'Multilingüe (ES/EN)', price: 450, monthly: false },
      'sip-starter':      { name: 'Sip Starter', price: 1500, monthly: true },
      'nutty-blend':      { name: 'Nutty Blend', price: 2100, monthly: true },
      'milkshake':        { name: '5$ Milkshake', price: 2900, monthly: true },
      'a-por-todo':       { name: 'A por todo', price: 5500, monthly: true }
    };

    var retainerIds = _cfg.retainerIds || ['sip-starter', 'nutty-blend', 'milkshake', 'a-por-todo'];
    var webIds = _cfg.webIds || ['shakefront-full', 'shakefront-lite'];

    function getCard(id) { return document.querySelector('[data-service="' + id + '"]'); }

    function toggle(id) {
      var card = getCard(id);
      if (!card) return;
      var type = card.getAttribute('data-type');

      if (type === 'core') {
        // Web packages are mutually exclusive
        if (webIds.indexOf(id) !== -1) {
          webIds.forEach(function(wid) {
            if (wid !== id && state.core.indexOf(wid) !== -1) {
              state.core.splice(state.core.indexOf(wid), 1);
            }
          });
        }
        var idx = state.core.indexOf(id);
        if (idx !== -1) state.core.splice(idx, 1);
        else state.core.push(id);
      } else if (type === 'addon') {
        var idx2 = state.addons.indexOf(id);
        if (idx2 !== -1) state.addons.splice(idx2, 1);
        else state.addons.push(id);
      } else if (type === 'retainer') {
        state.retainer = (state.retainer === id) ? null : id;
      }

      // Manual toggle breaks package — lose package discount
      state.activePackage = null;

      // Gap #5: Check service dependencies
      var deps = (_cfg.serviceDeps || {})[id];
      var allSelected = state.core.concat(state.addons);
      if (deps && deps.requires && allSelected.indexOf(id) !== -1) {
        deps.requires.forEach(function(reqId) {
          if (allSelected.indexOf(reqId) === -1) {
            // Auto-select required dependency
            var reqCard = getCard(reqId);
            if (reqCard) {
              var reqType = reqCard.getAttribute('data-type');
              if (reqType === 'core' && state.core.indexOf(reqId) === -1) state.core.push(reqId);
              else if (reqType === 'addon' && state.addons.indexOf(reqId) === -1) state.addons.push(reqId);
            }
          }
        });
      }

      recalculate();
    }

    function getEffectivePrice(id) {
      var svc = services[id];
      if (!svc) return { price: 0, status: 'normal' };
      var base = svc.price;
      var hasFull = state.core.indexOf('shakefront-full') !== -1;
      var hasFlashy = state.addons.indexOf('flashy-socials') !== -1 || state.core.indexOf('flashy-socials') !== -1;
      var hasButtery = state.addons.indexOf('buttery-1day') !== -1 || state.addons.indexOf('buttery-3days') !== -1;

      // Shakefront Full includes Milky Branding
      if (id === 'milky-branding' && hasFull) return { price: 0, status: 'included', label: 'INCLUIDO' };
      // Shakefront Full makes Glass Cup free
      if (id === 'glass-cup' && hasFull) return { price: 0, status: 'free', label: 'GRATIS' };
      // Shakefront Full discounts Flashy Socials
      if (id === 'flashy-socials' && hasFull) return { price: 870, status: 'discount', original: 1200 };
      // Silky Edits free with Full, Flashy, or Buttery
      if (id === 'silky-edits' && (hasFull || hasFlashy || hasButtery)) return { price: 0, status: 'free', label: 'GRATIS' };
      // Broadcast assets half price with Shakefront Full
      if (id === 'broadcast-assets' && hasFull) return { price: 1600, status: 'discount', original: 3200 };

      // Retainer discount on core projects
      if (state.retainer && (id === 'milky-branding' || webIds.indexOf(id) !== -1)) {
        var discounted = Math.round(base * 0.85);
        return { price: discounted, status: 'discount', original: base };
      }

      return { price: base, status: 'normal' };
    }

    function recalculate() {
      var allCards = document.querySelectorAll('.pricing-card');
      allCards.forEach(function(card) {
        card.classList.remove('selected', 'included', 'free', 'greyed');
      });

      state.core.forEach(function(id) { var c = getCard(id); if (c) c.classList.add('selected'); });
      state.addons.forEach(function(id) { var c = getCard(id); if (c) c.classList.add('selected'); });
      if (state.retainer) { var c = getCard(state.retainer); if (c) c.classList.add('selected'); }
      retainerIds.forEach(function(rid) {
        if (rid !== state.retainer) { var c = getCard(rid); if (c) c.classList.remove('selected'); }
      });

      // Apply conditional states
      var hasFull = state.core.indexOf('shakefront-full') !== -1;
      var hasFlashy = state.addons.indexOf('flashy-socials') !== -1;
      var hasButtery = state.addons.indexOf('buttery-1day') !== -1 || state.addons.indexOf('buttery-3days') !== -1;

      if (hasFull) {
        var mb = getCard('milky-branding');
        if (mb) { mb.classList.add('included', 'selected'); if (state.core.indexOf('milky-branding') === -1) state.core.push('milky-branding'); }
      }
      if (hasFull) { var gc = getCard('glass-cup'); if (gc && state.addons.indexOf('glass-cup') !== -1) gc.classList.add('free'); }
      if (hasFull || hasFlashy || hasButtery) { var se = getCard('silky-edits'); if (se && state.addons.indexOf('silky-edits') !== -1) se.classList.add('free'); }

      if (state.retainer) {
        var addonCards = document.querySelectorAll('[data-type="addon"]');
        addonCards.forEach(function(card) {
          card.classList.add('greyed');
          card.classList.remove('selected');
        });
        state.addons = [];
      }

      updatePackageHighlights();
      updatePriceDisplays();
      updateSummary();
    }

    var packages = _cfg.packages || {
      'full': { core: ['shakefront-full'], addons: ['flashy-socials', 'broadcast-assets', 'cold-brew', 'hosting-domain', 'glass-cup', 'silky-edits'] },
      'branding': { core: ['milky-branding'], addons: ['broadcast-assets'] }
    };

    function updatePackageHighlights() {
      document.querySelectorAll('.package-card').forEach(function(c) { c.classList.remove('selected'); });
      Object.keys(packages).forEach(function(pkgId) {
        var pkg = packages[pkgId];
        var allCore = pkg.core.every(function(id) { return state.core.indexOf(id) !== -1; });
        var allAddons = pkg.addons.every(function(id) { return state.addons.indexOf(id) !== -1; });
        if (allCore && allAddons) {
          var el = document.getElementById('pkg-' + pkgId);
          if (el) el.classList.add('selected');
        }
      });
    }

    function formatPrice(n) {
      return '€' + n.toLocaleString('es-ES');
    }

    function updatePriceDisplays() {
      Object.keys(services).forEach(function(id) {
        var display = document.querySelector('[data-price-display="' + id + '"]');
        if (!display) return;
        var eff = getEffectivePrice(id);
        if (eff.status === 'included' || eff.status === 'free') {
          display.innerHTML = '<span class="original-price">' + formatPrice(services[id].price) + '</span><span class="discount-price">' + (eff.label || 'GRATIS') + '</span>';
        } else if (eff.status === 'discount') {
          display.innerHTML = '<span class="original-price">' + formatPrice(eff.original) + '</span> <span class="discount-price">' + formatPrice(eff.price) + '</span>';
        } else {
          var suffix = services[id].monthly ? '<span style="font-size:0.7rem;opacity:0.6;">/mes</span>' : '';
          display.innerHTML = formatPrice(services[id].price) + suffix;
        }
      });
    }

    function updateSummary() {
      var linesEl = document.getElementById('summary-lines');
      var itemsEl = document.getElementById('summary-items');
      var emptyEl = document.querySelector('.summary-empty');
      var onetimeEl = document.getElementById('summary-onetime');
      var monthlyEl = document.getElementById('summary-monthly');

      var allSelected = state.core.concat(state.addons);
      if (state.retainer) allSelected.push(state.retainer);

      if (allSelected.length === 0) {
        if (emptyEl) emptyEl.style.display = 'block';
        if (itemsEl) itemsEl.style.display = 'none';
        return;
      }
      if (emptyEl) emptyEl.style.display = 'none';
      if (itemsEl) itemsEl.style.display = 'block';

      var accentColor = '#f0ff3d'; // Always Van Alva yellow on the proposal page
      var html = '';
      var totalOnetime = 0;
      var totalMonthly = 0;

      state.core.forEach(function(id) {
        var eff = getEffectivePrice(id);
        var s = services[id];
        if (!s) return;
        if (eff.status === 'included') {
          html += '<div class="line-item discount"><span class="li-name">' + s.name + '</span><span class="li-price">INCLUIDO</span></div>';
        } else if (eff.status === 'discount') {
          html += '<div class="line-item"><span class="li-name">' + s.name + ' <span style="font-size:0.75rem;opacity:0.6;text-decoration:line-through;">' + formatPrice(eff.original) + '</span></span><span class="li-price" style="color:' + accentColor + ';">' + formatPrice(eff.price) + '</span></div>';
          totalOnetime += eff.price;
        } else {
          html += '<div class="line-item"><span class="li-name">' + s.name + '</span><span class="li-price">' + formatPrice(eff.price) + '</span></div>';
          totalOnetime += eff.price;
        }
      });

      state.addons.forEach(function(id) {
        var eff = getEffectivePrice(id);
        var s = services[id];
        if (!s) return;
        var suffix = s.monthly ? '/mes' : '';
        if (eff.status === 'free') {
          html += '<div class="line-item discount"><span class="li-name">' + s.name + '</span><span class="li-price">GRATIS</span></div>';
        } else if (eff.status === 'discount') {
          html += '<div class="line-item"><span class="li-name">' + s.name + '</span><span class="li-price" style="color:' + accentColor + ';">' + formatPrice(eff.price) + suffix + '</span></div>';
          if (s.monthly) totalMonthly += eff.price; else totalOnetime += eff.price;
        } else {
          html += '<div class="line-item"><span class="li-name">' + s.name + (s.monthly ? ' /mes' : '') + '</span><span class="li-price">' + formatPrice(eff.price) + '</span></div>';
          if (s.monthly) totalMonthly += eff.price; else totalOnetime += eff.price;
        }
      });

      if (state.retainer) {
        var rs = services[state.retainer];
        if (rs) {
          html += '<div class="line-item"><span class="li-name">' + rs.name + ' /mes <span style="font-size:0.7rem;opacity:0.5;">(mín. 3 meses)</span></span><span class="li-price" style="color:' + accentColor + ';">' + formatPrice(rs.price) + '/mes</span></div>';
          totalMonthly += rs.price;
        }
      }

      // Apply package-exclusive discount (only when a package is actively selected)
      var pkgDiscountPct = 0;
      var pkgDiscountAmt = 0;
      if (state.activePackage && _cfg.packageDiscounts && _cfg.packageDiscounts[state.activePackage]) {
        pkgDiscountPct = _cfg.packageDiscounts[state.activePackage];
        pkgDiscountAmt = Math.round(totalOnetime * pkgDiscountPct / 100);
        html += '<hr class="summary-divider">';
        html += '<div class="line-item discount"><span class="li-name">Descuento de paquete (' + pkgDiscountPct + '%)</span><span class="li-price">-' + formatPrice(pkgDiscountAmt) + '</span></div>';
        totalOnetime -= pkgDiscountAmt;
      }

      if (linesEl) linesEl.innerHTML = html;

      if (totalOnetime > 0) {
        if (onetimeEl) { onetimeEl.style.display = 'flex'; document.getElementById('total-onetime').textContent = formatPrice(totalOnetime); }
      } else {
        if (onetimeEl) onetimeEl.style.display = 'none';
      }

      if (totalMonthly > 0) {
        if (monthlyEl) { monthlyEl.style.display = 'flex'; document.getElementById('total-monthly').textContent = formatPrice(totalMonthly) + '/mes'; }
      } else {
        if (monthlyEl) monthlyEl.style.display = 'none';
      }

      var combinedText = '';
      if (totalOnetime > 0 && totalMonthly > 0) {
        combinedText = formatPrice(totalOnetime) + ' + ' + formatPrice(totalMonthly) + '/mes';
      } else if (totalOnetime > 0) {
        combinedText = formatPrice(totalOnetime);
      } else {
        combinedText = formatPrice(totalMonthly) + '/mes';
      }
      var totalEl = document.getElementById('total-combined');
      if (totalEl) totalEl.textContent = combinedText;

      var stickyVal = document.getElementById('sticky-price-value');
      var stickyCount = document.getElementById('sticky-price-count');
      if (stickyVal) stickyVal.textContent = combinedText;
      var serviceCount = state.core.length + state.addons.length + (state.retainer ? 1 : 0);
      if (stickyCount) stickyCount.textContent = serviceCount + (serviceCount === 1 ? ' servicio' : ' servicios');
      updateStickyVisibility();
      updateTimeline();
    }

    // Dynamic timeline
    function updateTimeline() {
      var container = document.getElementById('dynamic-timeline');
      if (!container) return;
      var timelines = _cfg.serviceTimelines || {};
      var allSelected = state.core.concat(state.addons);
      if (allSelected.length === 0) {
        container.innerHTML = '<div style="text-align:center;opacity:0.3;font-size:0.8rem;padding:2rem;">Selecciona servicios para ver el cronograma</div>';
        return;
      }

      var phases = [];
      var totalWeeks = 0;
      allSelected.forEach(function(id) {
        var tl = timelines[id];
        if (tl) {
          phases.push(tl);
          totalWeeks += tl.weeks;
        }
      });

      if (phases.length === 0) {
        container.innerHTML = '';
        return;
      }

      var phasesHtml = phases.map(function(p, i) {
        return '<div class="timeline-phase" style="opacity:1;transform:none;transition-delay:' + (i * 0.1) + 's;">' +
          '<div class="phase-dot" style="background:#f0ff3d;"></div>' +
          '<div class="phase-name">' + p.name + '</div>' +
          '<div class="phase-duration">' + p.weeks + ' semanas</div>' +
          '<div class="phase-tooltip">' +
            '<div class="tt-name">' + p.name + '</div>' +
            '<div class="tt-duration">' + p.weeks + ' semanas</div>' +
          '</div>' +
        '</div>';
      }).join('');

      container.innerHTML =
        '<div class="timeline-track animated" style="max-width:900px;margin:0 auto;">' +
          '<div class="timeline-line"><div class="timeline-line-fill" style="width:100%;"></div></div>' +
          '<div class="timeline-phases">' + phasesHtml + '</div>' +
        '</div>' +
        '<div class="timeline-total">Duración total estimada: ~' + totalWeeks + ' semanas</div>';
    }

    // Sticky price bar
    var pricingSectionInView = false;
    var summaryBoxInView = false;
    var hasSelectedServices = false;

    function updateStickyVisibility() {
      var bar = document.getElementById('sticky-price-bar');
      if (!bar) return;
      hasSelectedServices = (state.core.length + state.addons.length + (state.retainer ? 1 : 0)) > 0;
      if (pricingSectionInView && !summaryBoxInView && hasSelectedServices) {
        bar.classList.add('visible');
      } else {
        bar.classList.remove('visible');
      }
    }

    function initStickyObservers() {
      var pricingCart = document.getElementById('pricing-cart');
      var pricingSummary = document.getElementById('pricing-summary');
      if (!pricingCart || !pricingSummary) return;

      var sectionObserver = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) { pricingSectionInView = entry.isIntersecting; updateStickyVisibility(); });
      }, { threshold: 0 });

      var summaryObserver = new IntersectionObserver(function(entries) {
        entries.forEach(function(entry) { summaryBoxInView = entry.isIntersecting; updateStickyVisibility(); });
      }, { threshold: 0.3 });

      sectionObserver.observe(pricingCart);
      summaryObserver.observe(pricingSummary);
    }

    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', function() { initStickyObservers(); updateTimeline(); });
    } else {
      initStickyObservers();
      updateTimeline();
    }

    // PDF generation
    var LOGO_DATA_URI = 'data:image/png;base64,';

    function downloadPDF() {
      var allSelected = state.core.concat(state.addons);
      if (state.retainer) allSelected.push(state.retainer);
      if (allSelected.length === 0) { alert('Selecciona al menos un servicio para generar el presupuesto.'); return; }

      var clientName = (_cfg.client && _cfg.client.name) || 'Cliente';
      var accentColor = '#f0ff3d'; // Always Van Alva yellow for PDF branding
      var paymentText = _cfg.paymentText || '70% al inicio del proyecto · 20% entrega de branding · 10% entrega final';
      var date = new Date().toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' });

      var rows = '';
      var totalOnetime = 0;
      var totalMonthly = 0;
      var savings = 0;

      state.core.forEach(function(id) {
        var eff = getEffectivePrice(id);
        var s = services[id];
        if (!s) return;
        var priceCell = '';
        if (eff.status === 'included') {
          priceCell = '<span style="color:#f0ff3d;">INCLUIDO</span>';
          savings += s.price;
        } else if (eff.status === 'discount') {
          priceCell = '<span style="text-decoration:line-through;color:#888;margin-right:8px;">' + formatPrice(eff.original) + '</span><span style="color:#f0ff3d;">' + formatPrice(eff.price) + '</span>';
          savings += eff.original - eff.price;
          totalOnetime += eff.price;
        } else {
          priceCell = formatPrice(eff.price);
          totalOnetime += eff.price;
        }
        rows += '<tr><td class="item-name">' + s.name + '</td><td class="item-price">' + priceCell + '</td></tr>';
      });

      state.addons.forEach(function(id) {
        var eff = getEffectivePrice(id);
        var s = services[id];
        if (!s) return;
        var suffix = s.monthly ? '/mes' : '';
        var priceCell = '';
        if (eff.status === 'free') {
          priceCell = '<span style="color:#f0ff3d;">GRATIS</span>';
          savings += s.price;
        } else if (eff.status === 'discount') {
          priceCell = '<span style="text-decoration:line-through;color:#888;margin-right:8px;">' + formatPrice(eff.original) + '</span><span style="color:#f0ff3d;">' + formatPrice(eff.price) + suffix + '</span>';
          savings += eff.original - eff.price;
          if (s.monthly) totalMonthly += eff.price; else totalOnetime += eff.price;
        } else {
          priceCell = formatPrice(eff.price) + suffix;
          if (s.monthly) totalMonthly += eff.price; else totalOnetime += eff.price;
        }
        rows += '<tr><td class="item-name">' + s.name + '</td><td class="item-price">' + priceCell + '</td></tr>';
      });

      if (state.retainer) {
        var rs = services[state.retainer];
        if (rs) {
          rows += '<tr><td class="item-name">' + rs.name + ' <span style="color:#888;font-size:12px;">(mensual, mín. 3 meses)</span></td><td class="item-price">' + formatPrice(rs.price) + '/mes</td></tr>';
          totalMonthly += rs.price;
        }
      }

      var w = window.open('', '_blank');
      if (!w) { alert('Permite ventanas emergentes para ver el presupuesto.'); return; }

      w.document.write('<!DOCTYPE html><html><head><meta charset="utf-8"><title>Presupuesto — Van Alva x ' + clientName + '</title>');
      w.document.write('<link href="https://fonts.googleapis.com/css2?family=Cascadia+Code:ital,wght@0,200..700;1,200..700&display=swap" rel="stylesheet">');
      w.document.write('<style>');
      w.document.write('* { margin: 0; padding: 0; box-sizing: border-box; }');
      w.document.write('body { font-family: "Inter", "Helvetica Neue", Arial, sans-serif; background: #000; color: #f0f0f0; min-height: 100vh; display: flex; justify-content: center; padding: 40px 20px; }');
      w.document.write('.page { max-width: 640px; width: 100%; }');
      w.document.write('.header { display: flex; justify-content: space-between; align-items: flex-start; margin-bottom: 48px; padding-bottom: 24px; border-bottom: 1px solid rgba(255,255,255,0.1); }');
      w.document.write('.brand-logo { height: 32px; width: auto; }');
      w.document.write('.brand-sub { font-family: "Cascadia Code", monospace; font-size: 11px; color: #888; margin-top: 6px; }');
      w.document.write('.date { font-size: 11px; color: #666; text-align: right; }');
      w.document.write('.title { font-family: "Cascadia Code", monospace; font-size: 16px; font-weight: 600; margin-bottom: 8px; color: ' + accentColor + '; text-transform: uppercase; letter-spacing: 0.05em; }');
      w.document.write('.client { font-size: 13px; color: #888; margin-bottom: 32px; }');
      w.document.write('table { width: 100%; border-collapse: collapse; margin-bottom: 32px; }');
      w.document.write('tr { border-bottom: 1px solid rgba(255,255,255,0.06); }');
      w.document.write('.item-name { padding: 14px 0; font-size: 14px; }');
      w.document.write('.item-price { padding: 14px 0; text-align: right; font-family: "Cascadia Code", monospace; font-weight: 600; font-size: 14px; white-space: nowrap; }');
      w.document.write('.totals { background: rgba(255,255,255,0.04); border: 1px solid rgba(255,255,255,0.08); border-radius: 8px; padding: 20px 24px; margin-bottom: 24px; }');
      w.document.write('.total-row { display: flex; justify-content: space-between; align-items: center; padding: 6px 0; }');
      w.document.write('.total-label { font-size: 14px; color: #aaa; }');
      w.document.write('.total-value { font-family: "Cascadia Code", monospace; font-size: 20px; font-weight: 600; color: ' + accentColor + '; }');
      w.document.write('.total-value.monthly { font-size: 16px; color: #ccc; }');
      w.document.write('.savings { text-align: right; font-size: 12px; color: #4a9; margin-top: 8px; }');
      w.document.write('.payment { margin-top: 32px; padding: 16px 20px; border-left: 3px solid rgba(240,255,61,0.3); font-size: 12px; color: #888; line-height: 1.8; }');
      w.document.write('.payment strong { color: #bbb; }');
      w.document.write('.footer { margin-top: 48px; padding-top: 16px; border-top: 1px solid rgba(255,255,255,0.06); font-size: 10px; color: #555; text-align: center; }');
      w.document.write('.actions { margin-top: 32px; text-align: center; }');
      w.document.write('.print-btn { background: ' + accentColor + '; color: #000; border: none; padding: 12px 32px; font-size: 14px; font-weight: 600; border-radius: 6px; cursor: pointer; font-family: inherit; }');
      w.document.write('.print-btn:hover { opacity: 0.85; }');
      w.document.write('@media print { .actions { display: none; } body { background: #fff; color: #222; padding: 20px; } .page { max-width: 100%; } .totals { background: #f8f8f0; border-color: #ddd; } .total-value { color: #222; } .total-value.monthly { color: #444; } .header { border-bottom-color: #ddd; } tr { border-bottom-color: #eee; } .payment { border-left-color: #ccc; color: #555; } .payment strong { color: #333; } .footer { border-top-color: #eee; color: #aaa; } .title { color: #222; } .client { color: #666; } .savings { color: #f0ff3d; } .brand-logo { filter: invert(1); } }');
      w.document.write('</style></head><body>');
      w.document.write('<div class="page">');
      w.document.write('<div class="header"><div><img src="' + LOGO_DATA_URI + '" class="brand-logo" alt="Van Alva"><div class="brand-sub">Studio de diseño y desarrollo</div></div><div class="date">' + date + '</div></div>');
      w.document.write('<div class="title">Presupuesto</div>');
      w.document.write('<div class="client">' + clientName + ' — Propuesta de servicios creativos</div>');
      w.document.write('<table>' + rows + '</table>');
      w.document.write('<div class="totals">');
      if (totalOnetime > 0) w.document.write('<div class="total-row"><span class="total-label">Inversión única</span><span class="total-value">' + formatPrice(totalOnetime) + '</span></div>');
      if (totalMonthly > 0) w.document.write('<div class="total-row"><span class="total-label">Mensual</span><span class="total-value monthly">' + formatPrice(totalMonthly) + '/mes</span></div>');
      if (savings > 0) w.document.write('<div class="savings">Ahorro total: ' + formatPrice(savings) + '</div>');
      w.document.write('</div>');
      var bi = (_cfg.bankInfo) || { bank: 'BBVA', iban: 'ES61 0182 2254 4402 0158 7969', bic: 'BBVAESMM', holder: 'Maria Almudena Martinez Pineda' };
      w.document.write('<div class="payment"><strong>Forma de pago</strong><br>' + paymentText + '<br><br><strong>' + bi.bank + ':</strong> ' + bi.iban + ' · BIC: ' + bi.bic + '</div>');
      w.document.write('<div class="actions"><button class="print-btn" onclick="window.print()">Guardar como PDF</button></div>');
      w.document.write('<div class="footer">Generado desde la propuesta de Van Alva · vanalva.io</div>');
      w.document.write('</div></body></html>');
      w.document.close();
    }

    function updatePaymentDisplay(pkgId) {
      var paymentEl = document.querySelector('.terms-highlight');
      if (!paymentEl) return;
      var pkgPayments = (_cfg.packagePayments || {})[pkgId];
      if (!pkgPayments || !pkgPayments.splits) return;
      var total = pkgPayments.total || 0;
      var html = pkgPayments.splits.map(function(s) {
        var amount = Math.round(total * s.percentage / 100);
        var label = s.trigger || s.label || '';
        return '<p><strong>' + s.percentage + '%</strong> — ' + label + (amount ? ' (€' + amount.toLocaleString('es-ES') + ')' : '') + '</p>';
      }).join('');
      paymentEl.innerHTML = html;
    }

    function selectPackage(pkgId) {
      state.core = [];
      state.addons = [];
      state.retainer = null;
      state.activePackage = pkgId; // Track active package for discount

      document.querySelectorAll('.package-card').forEach(function(c) { c.classList.remove('selected'); });

      var pkg = packages[pkgId];
      if (!pkg) return;

      pkg.core.forEach(function(id) { state.core.push(id); });
      if (state.core.indexOf('shakefront-full') !== -1 && state.core.indexOf('milky-branding') === -1) {
        state.core.push('milky-branding');
      }
      pkg.addons.forEach(function(id) { state.addons.push(id); });

      var pkgCard = document.getElementById('pkg-' + pkgId);
      if (pkgCard) pkgCard.classList.add('selected');

      recalculate();
      updatePaymentDisplay(pkgId);
    }

    return { toggle: toggle, downloadPDF: downloadPDF, selectPackage: selectPackage };
  })();

  var ServiceModal = (function() {
    var data = (_cfg.serviceModals) || {};

    var overlay = document.getElementById('service-modal-overlay');
    var currentService = null;

    function open(id) {
      var d = data[id];
      if (!d) return;
      currentService = id;
      var eyebrowEl = document.getElementById('modal-eyebrow');
      var titleEl = document.getElementById('modal-title');
      var priceEl = document.getElementById('modal-price');
      var descEl = document.getElementById('modal-desc');
      if (eyebrowEl) eyebrowEl.textContent = d.eyebrow;
      if (titleEl) titleEl.textContent = d.title;
      if (priceEl) priceEl.textContent = d.price;
      if (descEl) descEl.textContent = d.desc;

      var listEl = document.getElementById('modal-list');
      if (listEl) listEl.innerHTML = (d.includes || []).map(function(item) { return '<li>' + item + '</li>'; }).join('');

      var delSection = document.getElementById('modal-deliverables-section');
      var delEl = document.getElementById('modal-deliverables');
      if (d.deliverables && d.deliverables.length > 0) {
        if (delSection) delSection.style.display = 'block';
        if (delEl) delEl.innerHTML = d.deliverables.map(function(item) { return '<li>' + item + '</li>'; }).join('');
      } else {
        if (delSection) delSection.style.display = 'none';
      }

      if (overlay) {
        overlay.style.display = 'flex';
        document.body.style.overflow = 'hidden';
        requestAnimationFrame(function() { overlay.classList.add('active'); });
      }
    }

    function close() {
      if (!overlay) return;
      overlay.classList.remove('active');
      setTimeout(function() {
        overlay.style.display = 'none';
        document.body.style.overflow = '';
      }, 300);
    }

    function selectAndClose() {
      if (currentService) PricingCart.toggle(currentService);
      close();
    }

    document.addEventListener('keydown', function(e) {
      if (e.key === 'Escape') {
        var retainerOverlay = document.getElementById('retainer-overlay');
        if (retainerOverlay && retainerOverlay.classList.contains('active')) {
          RetainerPage.close();
        } else if (overlay && overlay.classList.contains('active')) {
          close();
        }
      }
    });

    return { open: open, close: close, selectAndClose: selectAndClose };
  })();

  var RetainerPage = (function() {
    var overlay = document.getElementById('retainer-overlay');

    function open() {
      if (!overlay) return;
      overlay.style.display = 'block';
      document.body.style.overflow = 'hidden';
      requestAnimationFrame(function() { overlay.classList.add('active'); });
      overlay.scrollTop = 0;
    }

    function close() {
      if (!overlay) return;
      overlay.classList.remove('active');
      setTimeout(function() {
        overlay.style.display = 'none';
        document.body.style.overflow = '';
      }, 300);
    }

    return { open: open, close: close };
  })();

  /* Terms Subtab Toggle */
  var TermsTabs = (function() {
    function switchTab(tab) {
      document.querySelectorAll('.terms-subtab').forEach(function(btn) {
        btn.classList.remove('active');
      });
      document.querySelectorAll('.terms-panel').forEach(function(panel) {
        panel.classList.remove('active');
      });
      var activeBtn = document.querySelector('.terms-subtab[onclick*="' + tab + '"]');
      if (activeBtn) activeBtn.classList.add('active');
      var activePanel = document.getElementById('terms-' + tab);
      if (activePanel) activePanel.classList.add('active');
    }
    return { switch: switchTab };
  })();
